// GT86 HUDs contain absolutely-positioned children. Keep their containers
// above the game canvas; the original `element.style = "<div..."` was invalid.
[modMenu2, modMenu3].forEach(function (panel) {
    panel.style.cssText = "position:fixed;inset:0;z-index:2147483000;pointer-events:none;";
});
const container = document.querySelectorAll(".range-slider");

for (let i = 0; i < container.length; i++) {
    const slider = container[i].querySelector('.Slider');
    const thumb = container[i].querySelector('.slider-thumb');
    const tooltip = container[i].querySelector('.tooltip');
    const progress = container[i].querySelector('.progress');

    function customSlider() {
        const maxVal = slider.getAttribute("max");
        const val = (slider.value / maxVal) * 100 + "%";
        tooltip.innerHTML = slider.value;
        progress.style.width = val;
        thumb.style.left = val;
    }
    customSlider();
    slider.addEventListener("input", () => {
        customSlider();
    })
}
