            var sendChats = true;

            function formatSentence(sentence) {
                // 1. Capitalize the first letter of the sentence and after a period
                sentence = sentence.replace(/(^|[.!?><=+&%$@^]\s+)(\w)/g, function(match, p1, p2) {
                    return p1 + p2.toUpperCase();
                });

                // 2. Automatic comma placement
                sentence = sentence.replace(/(\w+)\s*([.,?!])\s*(\w+)/g, function(match, p1, p2, p3) {
                    if (p2 === ',' && p1.charAt(p1.length - 1) !== ',') {
                        return p1 + ', ' + p3;
                    } else if (p2 !== ',' && p1.charAt(p1.length - 1) === ',') {
                        return p1.slice(0, -1) + p2 + ' ' + p3;
                    } else {
                        return match;
                    }
                });

                // 3. Automatic period at the end of the sentence
                if (!/[.?!;:<>[\]{}=+\-]$/.test(sentence)) {
                    sentence += '.';
                }

                // 5. Automatic removal of leading and trailing spaces
                sentence = sentence.trim();

                // 6. Automatic removal of spaces between words
                sentence = sentence.replace(/\s+/g, ' ');

                // 7. Add a space after question marks and exclamation marks
                sentence = sentence.replace(/(\w+[?!])(\S+)/g, function(match, p1, p2) {
                    return p1 + ' ' + p2.charAt(0).toUpperCase() + p2.slice(1);
                });

                // Remove spaces before commas and periods
                sentence = sentence.replace(/\s+([,.])/g, '$1');

                // Add a space after commas and periods if not already present
                sentence = sentence.replace(/([,.])(\S)/g, '$1 $2');

                // Remove spaces before exclamation marks and question marks
                sentence = sentence.replace(/\s+([?!])/g, '$1');

                // Add a space before exclamation marks and question marks if not already present
                sentence = sentence.replace(/(\S)([?!])/g, '$1 $2');

                return sentence;
            }
            function sendChat(message) {
                let command = function(chat) {
                    return message === "." + chat;
                };
                if (command("dcc")) {
                    let chickens = [];
                    let timeout = 0;
                    players.forEach((i)=>{
                        tmpObj = players[i];
                        if (tmpObj != player && tmpObj.visible) {
                            chickens.push({
                                name: tmpObj.name,
                                timeout: timeout
                            });
                            timeout += 600;
                        }
                    })
                    chickens.forEach((ahaha)=>{
                        setTimeout(()=>{
                            io.send("ch", "!c!dc user " + ahaha.name);
                        }
                                   , ahaha.timeout);
                    }
                                    );
                } else if (command("exit")) {
                    io.send("ch", "Disconnencting...");
                    setTimeout(()=>{
                        io.close();
                    }
                               , 500);
                } else {
                    if (getEl("chatc").checked && !singing.toggle && !singing.audio) {
                        io.send("ch", (formatSentence(message)).slice(0, 30));
                    } else {
                        io.send("ch", message.slice(0, 30));
                    }
                }
            }

            window.ValueSendChat = sendChat;
            window.ValueSendChatRaw = function (message) { io.send("ch", String(message).slice(0, 30)); };

