            function playMusic(value) {
                let song = songs[parseInt(value) - 1]
                if (singing.audio) {
                    singing.audio.currentTime = 0;
                    singing.audio.pause();
                }
                singing.name = song.name;
                singing.audio = new Audio(song.src);
                singing.timeouts.forEach(e => clearTimeout(e));
                singing.timeouts = [];

                if (singing.toggle && singing.audio) {
                    singing.audio.onended = function() {
                        singing.toggle = false;
                        singing.audio.currentTime = 0;
                        singing.audio.pause()
                    };
                    if (singing.audio.paused) {
                        singing.audio.play();
                    }
                    for (let time in song.sync) {
                        let message = song.sync[time];
                        singing.timeouts.push(setTimeout(() => {
                            io.send("ch", "" + message ?? "");
                        }, time));
                    }
                } else {
                    singing.audio && (singing.audio.currentTime = 0, singing.audio.pause());
                }
            }

            function toggleSing(value) {
                playMusic(value);
                singing.toggle = !singing.toggle;
                singing.timeouts.forEach(e => clearTimeout(e));
                singing.timeouts = [];
                let song = songs[parseInt(value) - 1];
                if (singing.toggle && singing.audio) {
                    singing.audio.onended = function() {
                        singing.toggle = false;
                        singing.audio.currentTime = 0;
                        singing.audio.pause()
                    };
                    if (singing.audio.paused) {
                        singing.audio.play();
                    }
                    for (let time in song.sync) {
                        let message = song.sync[time];
                        singing.timeouts.push(setTimeout(() => {
                            io.send("ch", "" + message ?? "");
                        }, time));
                    }
                } else {
                    singing.audio && (singing.audio.currentTime = 0, singing.audio.pause());
                }
            }

