            let replaceObjCon = true;
            function akaE() {
                for (let i = 0; i < 3; i++) {

                    for (let j = 0; j < 3; j++) {
                        let sliderWrapper = document.createElement("div");
                        sliderWrapper.className = "switch";
                        let slider = document.createElement("input");
                        slider.type = "checkbox";
                        slider.id = "switch" + i + j;
                        slider.onchange = function() {
                            document.querySelector('#label' + this.id).innerText = this.checked ? "True" : "False";
                        };
                        sliderWrapper.appendChild(slider);
                        let sliderDiv = document.createElement("div");
                        sliderDiv.className = "slider";
                        let sliderLabel = document.createElement("label");
                        sliderLabel.id = 'label' + slider.id;
                        sliderLabel.innerText = "False";
                        sliderDiv.appendChild(sliderLabel);
                        sliderDiv.onclick = function() {
                            let input = this.previousSibling;
                            input.checked = !input.checked;
                            input.onchange();
                        };
                        sliderWrapper.appendChild(sliderDiv);
                    }
                }
            }
            akaE();

            // BETTER TIMEOUT FOR POWERFULL:
            function betterSetTimeout(callback, delay, ...args) {
                return new Promise((resolve, reject) => {
                    setTimeout(() => {
                        try {
                            const result = callback(...args);
                            resolve(result);
                        } catch (error) {
                            reject(error);
                        }
                    }, delay);
                }).then((result)=>{
                    return result;
                }).catch((e)=>{
                    console.error(e);
                });
            }
            //CURSOR ID:
            function cursorChange() {
                if (getEl("cursor").value) {
                    if (getEl("cursor").value == "1") {
                        return `cursor: auto;`;
                    } else if (getEl("cursor").value == "2") {
                        return `cursor: crosshair`;
                    } else {
                        return `cursor: none`;
                    }
                }
            }
            getEl("cursor").onchange = function() {
                document.body.style = `
                   ${cursorChange()}
                `;
            }

            // TIMEOUT2:
            function SetTimeout(callback, delay, ...args) {
                const start = Date.now();

                function checkTime() {
                    const elapsed = Date.now() - start;
                    if (elapsed >= delay) {
                        callback(...args);
                    } else {
                        requestAnimationFrame(checkTime);
                    }
                }

                requestAnimationFrame(checkTime);
            }

            function calcAngle(xs, ys, xe, ye) {
                return Math.atan2(ye - ys, xe - xs);
            }
            var replaceObjects = [];
            var killObjs = false;
            // KILL OBJECT:

            let breakTracks = [];
            function placeGrind() {
                let count = 0;
                for (let i = 0; ; i += Math.PI / 2) {
                    count++;
                    if (count > 4) {
                        break;
                    }
                    checkPlace(player.items[5] ? 5 : 1, i);
                }
            }
            getEl("grind").onclick = function() {
                setTickout (() => {
                    placeGrind();
                }, 1)
            }
            ;

            var counts1 = 0;
            let configs = {
                weaponCode: 0,
                antiBull: 0,
                antiBull2: 0,
                waitHit: false,
            };
            function caf(e, t) {
                try {
                    return Math.atan2((t.y2 || t.y) - (e.y2 || e.y), (t.x2 || t.x) - (e.x2 || e.x));
                } catch (e) {
                    return 0;
                }
            }
            function fgd(a, b){
                return Math.sqrt(Math.pow((b.y2-a[2]),2)+Math.pow((b.x2-a[1]),2));
            }
            function fgdo(a, b){
                return Math.sqrt(Math.pow((b.y-a.y),2)+Math.pow((b.x-a.x),2));
            }

            class GameObjectsReplacer {
                constructor(UTILS, findObj, dist, items, sid) {
                    this.UTILS = UTILS;
                    this.findObj = findObj;
                    this.items = items;
                    this.sid = sid;
                    this.dist2 = dist;
                    this.aim = 0;
                    this.near = near;
                    this._value = undefined;
                    this.inTrap = false;
                    this.replaced = false;
                    this.antiTrapped = false;
                    this.objectPredict = [];
                    this.info = {};
                    this.toReturn = undefined;
                    this.dist = function (a, b){
                        return Math.sqrt(Math.pow((b.y2 || b.y) - a[2], 2) + Math.pow((b.x2 || b.x) - a[1], 2))
                    }
                    this.notFast = function() {
                        return player.weapons[1] == 10 && ((this.info.health > items.weapons[player.weapons[0]].dmg) || player.weapons[0] == 5);
                    }
                    this.distances = function (a, b, a2, b2, a3, b3, nearest, value) {
                        let toReturn;

                        toReturn = UTILS.getDist(a, nearest, a2, b2) - UTILS.getDist(b, nearest, a2, b2);

                        if (value) {
                            toReturn = UTILS.getDist(a, nearest, a2, b2) - UTILS.getDist(b, nearest, a3, b3);
                        }

                        return toReturn;
                    };
                    this.checkSecond = function (id, angle) {
                        let item = items.list[player.items[id]];
                        let scale = 35 + item.scale + (item.placeOffset || 0);
                        let x = player.x2 + Math.cos(angle) * scale;
                        let y = player.y2 + Math.sin(angle) * scale;
                        for(let i = 0; i < this.objectPredict.length; i++) {
                            let _ = this.objectPredict[i];
                            if(_ && Math.hypot(_.y - y, _.x - x) <= scale + _.scale) {
                                return false;
                            }
                        }
                        return true;
                    }
                    this.forPlace = function (id, start, repeat, plus, radian, forEachOrFor, each = undefined) {
                        const type = new Set([null, NaN, undefined, 0, 1, 2, ""]);
                        if (forEachOrFor && each !== undefined) {
                            if (type.has(each)) {
                                let aim = this.UTILS.getDirect(findObj, player, 0, 2);
                                place(id, aim);
                            } else {
                                each.forEach((tmp) => {
                                    let aim = this.UTILS.getDirect(tmp, player, 0, 2);
                                    place(id, aim);
                                });
                            }
                        } else {
                            for (let gz = start; gz <= repeat; gz += plus) {
                                let relAim = radian + gz;
                                place(id, relAim);
                            }
                        }
                    };
                    this.placer = function (id, first = -(Math.PI / 2), repeat = (Math.PI / 2), plus = (Math.PI / 18), radian, radian2, replacer) {
                        try {
                            let item = items.list[player.items[id]];
                            let tmpS = player.scale + item.scale + (item.placeOffset || 0);
                            let counts = {
                                attempts: 0,
                                placed: 0
                            };
                            let tmpObjects = [];
                            gameObjects.forEach((p) => {
                                tmpObjects.push({
                                    x: p.x,
                                    y: p.y,
                                    active: p.active,
                                    blocker: p.blocker,
                                    scale: p.scale,
                                    isItem: p.isItem,
                                    type: p.type,
                                    colDiv: p.colDiv,
                                    getScale: function(sM, ig) {
                                        sM = sM || 1;
                                        return this.scale * ((this.isItem || this.type == 2 || this.type == 3 || this.type == 4) ? 1: (0.6 * sM)) * (ig ? 1 : this.colDiv);
                                    },
                                });
                            });
                            for (let i = first; i < repeat; i += plus) {
                                counts.attempts++;
                                let relAim = radian + i;
                                let tmpX = player.x2 + tmpS * Math.cos(relAim);
                                let tmpY = player.y2 + tmpS * Math.sin(relAim);
                                let cantPlace = tmpObjects.find((tmp) => tmp.active && UTILS.getDistance(tmpX, tmpY, tmp.x, tmp.y) < item.scale + (tmp.blocker ? tmp.blocker : tmp.getScale(0.6, tmp.isItem)));
                                if (cantPlace) continue;
                                if (item.id != 18 && tmpY >= config.mapScale / 2 - config.riverWidth / 2 && tmpY <= config.mapScale / 2 + config.riverWidth / 2) continue;
                                place(id, relAim, 1);
                                tmpObjects.push({
                                    x: tmpX,
                                    y: tmpY,
                                    active: true,
                                    blocker: item.blocker,
                                    scale: item.scale,
                                    isItem: true,
                                    type: null,
                                    colDiv: item.colDiv,
                                    getScale: function() {
                                        return this.scale;
                                    },
                                });
                                if (UTILS.getAngleDist(near.aim2, relAim) <= 1) {
                                    counts.placed++;
                                }
                            }
                            if (counts.placed > 0 && replacer && item.dmg) {
                                if (near.dist2 <= items.weapons[player.weapons[0]].range + (player.scale * 1.8) && configs.spikeTick) {
                                    instaC.canSpikeTick = true;
                                }
                            }
                        } catch (err) {
                            log(err);
                        }
                    };
                    this.protect = function (object, findObj, sid) {
                        let spike = gameObjects.find((e) => Math.hypot(e.y - player.y, e.x - player.x) <= 212 && /spik/.test(e.name) && e.active && e.owner.sid != player.sid);
                        let spikes = gameObjects.filter((e) => Math.hypot(e.y - player.y, e.x - player.x) <= 212 && /spik/.test(e.name) && e.active && e.owner.sid != player.sid).sort(function (a, b) {
                            return (UTILS.getDist(a, player, 0, 2) - UTILS.getDist(b, player, 0, 2));
                        })[0];
                        let range = items.weapons[player.weapons[0]].range + 70;
                        if (findObj) {
                            if (tmpObj == player) {
                                tmpObj.damaged = tmpObj.oldHealth - tmpObj.health;
                                if ((spike || spikes) && tmpObj.health < 56 || (spike || spikes) && tmpObj.health < 66 && tmpObj.skinIndex != 6 && player.weaponVariant > 0) {
                                    buyEquip(6, 0);
                                } else {
                                    if (tmpObj.health < 56 || tmpObj.health < 66 && tmpObj.skinIndex != 6 && player.weaponVariant > 0) {
                                        buyEquip(6, 0);
                                    } else {
                                        if (this.dist2 <= 222) {
                                            buyEquip(6, 0);
                                            this.placer(2, 0, (Math.PI * 2), (Math.PI / 18), near.aim2, near.aim2, 1);
                                        }
                                    }
                                }
                            }
                        }
                    };
                    this.replacer = function (n, object) {
                        if (!n) return;
                        if (!inGame) return;

                        const scalarProduct = (a, b) => {
                            return Math.cos((a * b) / (a * b));
                        }, magnitude = (a) => {
                            return Math.sqrt(a.x ** 2 + a.y ** 2 + nEA);
                        };
                        const angles = Math.acos(scalarProduct(nEy, player) / (magnitude(findObj) * magnitude(player)));
                        let objAim = this.UTILS.getDirect(findObj, player, 0, 2);
                        let objDst = this.UTILS.getDist(findObj, player, 0, 2);
                        let range = items.weapons[player.weapons[0]].range + 70;
                        let tmpAim = Math.atan2(n.y - player.y, n.x - player.x) + Math.PI;
                        let radian = objAim || tmpAim;
                        let radianToPlace = tmpAim || tryChunk(angles);
                        let objAimInRadians = objAim * Math.PI / 180;
                        let radians = objAimInRadians + Math.PI / 1.5;
                        let radianPlace = radians || objAim;
                        let weaponReady = player.reloads[player.weapons[0]] <= 1;
                        let _value = 0;
                        let _distance = this.distances;
                        let _UTILS = this.UTILS;
                        let nearObject = function (func) {
                            let functions = {
                                scale: n.scale,
                                objectX: n.x,
                                objectY: n.y,
                                gameObj: gameObjects,
                            };

                            return functions[func];
                        };
                        let gearDmgs = [0.25, 0.45].map((val) => val * items.weapons[player.weapons[0]].dmg * n.scale - (near.scale + nearObject("scale")));
                        let setsForGroup = new Set([2, 4]); // Lazy
                        const perfectAim = ((player.canSee(n) && objDst <= 184 && setsForGroup.has(n.group.id) && (player.moveDir == undefined || Math.hypot(n.x - player.x2, n.y - n.y) <= 72)) ? Math.hypot(n.x - player.x2, n.y - n.y) : objAim);
                        const aiming = Math.hypot(n.x - player.x, n.y - n.y);
                        const aimTo = Math.hypot(n.x - player.x2, n.y - n.y);
                        if (this.dist2 <= 600 && enemy.length) {
                            if (objDst <= 400 && this.dist2 <= 400) {

                                for (let o = Math.PI / 2; o < Math.PI / 2; o += Math.PI / 18) {
                                    radianPlace = o;
                                }

                                for (let _ = nEA - Math.PI / 3; _ < nEA + Math.PI / 3; _ += Math.PI / 18) {
                                    radian = _;
                                    radianToPlace = objAim + _;
                                }

                                if (this.dist2 <= 280 && objDst <= 280) {

                                    if (traps.inTrap) {
                                        this.placer(2, -(Math.PI / 2), (Math.PI / 2), (Math.PI / 18), objAim + Math.PI);
                                    }

                                    if (["pit trap"].includes(n.name)) {
                                        if (this.dist2 <= 200 && objDst <= 200) {
                                            place(2, aiming);
                                            waitSpikeTick2 = true;

                                            if (this.dist2 <= 184 && objDst <= 184) {
                                                if (weaponReady && (objDst - this.dist2) == 145) checkPlace(2, objAim);
                                            } else {
                                                this.placer(2, 0, (Math.PI * 2), (Math.PI / 24), objAim, objAim);
                                            }
                                        }
                                    }

                                    if ((this.dist2 > 245 && objDst > 245) && (this.dist2 <= 280 && objDst <= 280)) {
                                        this.placer(2, (nEA - Math.PI / 3), (nEA + Math.PI / 3), (Math.PI / 18), nEA, nEA);
                                    }
                                    else {

                                        if (objDst <= 145 && weaponReady) this.placer(2, 0, (Math.PI * 2), (Math.PI / 24), objAim, objAim);

                                        if (/spik/.test(n.name) && this.dist2 <= 112 && objDst <= 80) checkPlace(2, perfectAim);
                                        else {
                                            if (objDst <= 212 && this.dist2 <= 212) {
                                                if (objDst <= 70) {
                                                    checkPlace(2, objAim + Math.PI);
                                                }
                                            }
                                        }

                                        if (["pit trap"].includes(n.name)) {
                                            place(2, aiming);

                                            if (this.dist2 <= 232) {
                                                checkPlace(2, radianPlace);
                                                this.placer(2, (0), (Math.PI * 2), (Math.PI / 24), objAim, objAim);
                                            } else {
                                                player.items[4] == 15 && this.placer(4, (Math.PI / 2), (Math.PI / 2), (Math.PI / 18), objAim + Math.PI);
                                            }
                                        } else if (/spik/.test(n.name)) {
                                            place(2, aiming);

                                            if (this.dist2 <= 222) {
                                                checkPlace(2, aimTo);

                                                this.placer(2, (nEA - Math.PI / 3), (nEA + Math.PI / 3), (Math.PI / 18), nEA, nEA);
                                            } else {
                                                player.items[4] == 15 && this.placer(4, (Math.PI / 2), (Math.PI / 2), (Math.PI / 18), objAim + Math.PI);
                                            }
                                        } else {
                                            checkPlace(2, aiming);

                                            if (this.dist2 <= 133 && weaponReady) this.placer(2, (Math.PI / 2), (Math.PI / 2), (Math.PI / 18), objAim + Math.PI);

                                            if (this.dist2 <= 225) {
                                                checkPlace(2, radian);
                                            } else {
                                                player.items[4] == 15 && this.placer(4, (Math.PI / 2), (Math.PI / 2), (Math.PI / 18), objAim + Math.PI);
                                            }
                                        }
                                    }
                                }

                                if (this.dist2 >= 205 && weaponReady && (ticks.tick % 2) === 0) {
                                    player.items[4] == 15 && this.placer(4, 0, (2 * Math.PI), (Math.PI / 9), objAim, objAim);
                                }
                            }
                        }
                    };
                }
            };

            window.spikeTickDst = 200;
            function killObject(sid, tmpObj, angle) {
                tmpObj = findObjectBySid(sid);
                var objDst = UTILS.getDist(tmpObj, player, 0, 2);
                let eRep = function() {
                    let range = items.weapons[player.weapons[0]].range + 70;
                    if (near.dist2 <= range) {
                        checkPlace(2, objAim)
                        waitSpikeTick = true;
                        if (near.dist <= range) {
                            checkPlace(2, objAim)
                            waitSpikeTick = true;
                        } else {
                            checkPlace(2, Math.PI + UTILS.getDirection(findObj, player, 0, 2))
                        }
                        if (near.dist2 >= range && near.dist2 <= 210) {
                            checkPlace(2, objAim + Math.PI / 1.5)
                        } else {
                            checkPlace(2, objAim)
                            waitSpikeTick = true;
                        }
                        if (near.dist2 <= range && near.dist2 <= 210) {
                            checkPlace(2, objAim + Math.PI / 1.5)
                            waitSpikeTick = true
                        } else {
                            if (near.dist2 <= 250) {
                                checkPlace(2, objAim + Math.PI / 1.5)
                            } else {
                                if (near.dist2 <= 245) {
                                    checkPlace(2, objAim)
                                } else {
                                    checkPlace(2, objAim + rad(28))
                                }
                            }
                        }
                    }
                }
                if (getEl("grind").checked) {
                    setTickout (() => {
                        placeGrind();
                    }, 1)
                }
                ;
                let weaponReady = player.reloads[player.weapons[0]] <= 1;
                let trap = gameObjects.filter(e => e.trap && e.active && e.isTeamObject(player) && UTILS.getDist(e, near, 0, 2) <= (near.scale + e.getScale() + 5)).sort(function (a, b) {
                    return UTILS.getDist(a, near, 0, 2) - UTILS.getDist(b, near, 0, 2);
                })[0];
                if (near.dist2 <= 320) {
                    if (enemy.length){
                        if(player.reloads[player.weapons[0]] == (0 || 1)){
                            for (let gz = 0; gz < 24; gz++) {
                                angle = gz * 8 * (gz%2?-1:1)/180*Math.PI+ (nEA != null && nEA != undefined ? nEA : near.aim2);
                            }
                            if (near.dist2 > 140) {
                                place(2, rad(fixAngle(angle)*3));
                                checkPlace(2, calcAngle(angle))
                            } else {
                                place(2, Math.hypot(tmpObj.x - player.x, tmpObj.y - tmpObj.y));
                                let range = items.weapons[player.weapons[0]].range + 70;
                                let range2 = items.weapons[player.weapons[0]].range <= 70;
                                if (objDst <= range && near.dist2 <= range) {
                                    waitSpikeTick = true;
                                    eRep();
                                    if (objDst <= range && near.dist2 <= range && objDst <= 210) {
                                        waitSpikeTick2 = true;
                                        place(2, calcAngle(angle))
                                    } else {
                                        if (objDst <= 200 && objDst <= range && near.dist2 <= range) {
                                            waitSpikeTick2 = true
                                            checkPlace(2, rad(fixAngle(angle)*3));
                                        }
                                    }
                                }
                            }
                        } else {
                            if (trap) {
                                let a = Math.hypot(trap.y-player.y, trap.x-player.x);
                                if(a > fgd(enemy, player)){
                                    let b = Math.atan2(player.y - trap.y, player.x - trap.x)
                                    , c = trap.x + ((35 + items.list[player.items[2]].scale) * Math.cos(b))
                                    , d = trap.y + ((35 + items.list[player.items[2]].scale) * Math.sin(b));
                                    place(2, Math.atan2(d - player.y, c - player.x));
                                    if (near.dist2 <= 50) {
                                        checkPlace(2, Math.hypot(tmpObj.x - player.x, tmpObj.y - tmpObj.y));
                                    }
                                } else {
                                    place(2, Math.hypot(tmpObj.x - player.x, tmpObj.y - tmpObj.y));
                                }
                            } else {
                                let o = 0;
                                for (let i=enemy-Math.PI/3; i<enemy+Math.PI/3; i+=Math.PI/18){
                                    o = i;
                                }
                                if (o != 0 && near.dist2 <= 80)
                                    place(2, o);
                                else
                                    place(2, near.aim2);
                            }
                        }

                        if (player.items[4] == 15){
                            for (let i=0; i<2*Math.PI; i+=Math.PI/9){
                                checkPlace(4, i);
                            }
                        }
                    }
                }
                objectManager.disableBySid(sid)
            };

            // UPDATE SCORE DISPLAY:
