            function renderSkin(index, ctxt, parentSkin, owner) {
                tmpSkin = skinSprites[index];
                if (!(tmpSkin = skinSprites[index + ((getEl("textures").value == "1") ? "lol" : getEl("textures").value == "2" ? "lel" : getEl("textures").value == "3" ? "lal" : getEl("textures").value == "4" ? "lpl" : getEl("textures").value == "5" ? "lql" : 0)])) {
                    var tmpImage = new Image();
                    tmpImage.onload = function() {
                        this.isLoaded = true;
                        this.onload = null;
                    }
                    ;
                    tmpImage.src = getTexturePackImg(index, "hat")
                    skinSprites[index + ((getEl("textures").value == "1") ? "lol" : getEl("textures").value == "2" ? "lel" : getEl("textures").value == "3" ? "lal" : getEl("textures").value == "4" ? "lpl" : getEl("textures").value == "5" ? "lql" : 0)] = tmpImage;
                    tmpSkin = tmpImage;
                }
                var tmpObj = parentSkin || skinPointers[index];
                if (!tmpObj) {
                    for (var i = 0; i < hats.length; ++i) {
                        if (hats[i].id == index) {
                            tmpObj = hats[i];
                            break;
                        }
                    }
                    skinPointers[index] = tmpObj;
                }
                if (tmpSkin.isLoaded)
                    ctxt.drawImage(tmpSkin, -tmpObj.scale / 2, -tmpObj.scale / 2, tmpObj.scale, tmpObj.scale);
                if (!parentSkin && tmpObj.topSprite) {
                    ctxt.save();
                    ctxt.rotate(owner.skinRot);
                    renderSkin(index + "_top", ctxt, tmpObj, owner);
                    ctxt.restore();
                }
            }
