            // UPDATE PLAYER ITEM VALUES:
            let isItemSetted = [];

            function updateItemCountHTML(index=undefined) {
                // On the main menu `player` and the action bar items do not
                // exist yet. changeCom(true) runs here when a visual mode is
                // picked in the menu; without this guard it throws and aborts
                // before the on-screen label (e.g. "ms / (c) King Hans") is
                // configured, so the label never shows in-game.
                if (!player) return;
                for (let i = 0; i < items.list.length; ++i) {
                    let id = items.list[i].group.id;
                    let tmpI = items.weapons.length + i;
                    if (!isItemSetted[tmpI]) {
                        isItemSetted[tmpI] = document.createElement("div");
                        isItemSetted[tmpI].id = "itemCount" + tmpI;
                        getEl("actionBarItem" + tmpI).appendChild(isItemSetted[tmpI]);
                        isItemSetted[tmpI].style = `
                    display: block;
                    position: absolute;
                    padding-left: 5px;
                    font-size: 2em;
                    color: #fff;
                    `;
                        if (i < 3) {
                            isItemSetted[tmpI].innerHTML = Math.floor(player.food / items.list[i].req[1]);
                        } else {
                            isItemSetted[tmpI].innerHTML = player.itemCounts[id] || 0;
                        }
                    } else {
                        if (index == id) {
                            isItemSetted[tmpI].innerHTML = player.itemCounts[index] || 0;
                        }
                        if (index == undefined) {
                            if (i < 3) {
                                isItemSetted[tmpI].innerHTML = Math.floor(player.food / items.list[i].req[1]);
                            }
                        }
                    }
                    if (getEl("combat").value == "0" || getEl("combat").value == "ae" || getEl("combat").value == "EwV" || getEl("combat").value == "WasdMode" || getEl("combat").value == "TesterMode" || getEl("combat").value == "Oldae" || getEl("combat").value == "hae" || getEl("combat").value == "devs" || getEl("combat").value == "jet" || getEl("combat").value == "hans" || getEl("combat").value == "gt86" || getEl("combat").value == "goofy") {
                        if (isItemSetted[tmpI].style.display == "block") {
                            isItemSetted[tmpI].style.display = "none";
                        }
                    } else {
                        if (isItemSetted[tmpI].style.display == "none") {
                            isItemSetted[tmpI].style.display = "block";
                        }
                    }
                }
            }

